	-- Data anf Pointer Registers
	process(clk)
	begin
		if rising_edge(clk) then
			if (put and not ful_i) = '1' then
				Dat <= din & Dat(0 to DEPTH-2);
			end if;
		end if;
	end process;

	process(clk)
	begin
		if rising_edge(clk) then
			if rst = '1' then
				Ptr <= (others => '1');
			else
				if (put and not ful_i) /= (got and vld_i) then
					if (put and not ful_i) = '1' then
						Ptr <= Ptr + 1;
					else
						Ptr <= Ptr - 1;
					end if;
				end if;
			end if;
		end if;
	end process;

