	dout   <= Dat(to_integer(Ptr(Ptr'left-1 downto 0)));
	vld_i  <= not Ptr(Ptr'left);
	ful_i  <= vld_i when (Ptr(Ptr'left-1 downto 0) and to_unsigned(DEPTH-1, Ptr'length-1)) = DEPTH-1 else '0';
	vld    <= vld_i;
	ful    <= ful_i;
	fill   <= std_logic_vector(Ptr);

end rtl;

